def structured_call(prompt, schema):
    raw = call_provider(prompt, response_format=schema)
    try:
        return schema.model_validate_json(raw), 0, None
    except ValidationError as e:
        # ONE repair attempt with error context
        raw2 = call_provider(
            prompt + f"\n\nPrevious output failed: {e}\nSchema:\n{schema.model_json_schema()}",
            response_format=schema,
        )
        try:
            return schema.model_validate_json(raw2), 1, None
        except ValidationError as e2:
            logger.error("parse-fail-twice", schema=schema.__name__, raw=raw2, error=str(e2))
            raise
